import{_ as t,o as l,c as i,a2 as e}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"自选","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"app-guide/watchlist.md","filePath":"zh-CN/app-guide/watchlist.md"}'),r={name:"app-guide/watchlist.md"};function o(s,a,n,d,h,p){return l(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="自选" tabindex="-1">自选 <a class="header-anchor" href="#自选" aria-label="Permalink to &quot;自选&quot;">​</a></h1><p>自选是用户手动收藏的股票、期权、ETF 等标的列表，方便快速查看行情和访问标的详情页。入口在 App 底部导航「关注」Tab 的「自选」子页。自选数据与账号绑定，登录同一账号后在手机、平板、桌面端均自动同步；数量上限取决于账户等级，普通用户约 200 支，接近上限时 App 会提示。</p><h2 id="分组与筛选" tabindex="-1">分组与筛选 <a class="header-anchor" href="#分组与筛选" aria-label="Permalink to &quot;分组与筛选&quot;">​</a></h2><p>列表顶部提供多个筛选 Tab：</p><ul><li><strong>全部</strong>：显示所有自选标的</li><li><strong>美股 / 港股</strong>：按市场快速筛选</li><li><strong>持仓</strong>：仅显示当前持有仓位的自选标的</li><li><strong>自定义分组</strong>：用户自行创建和命名的分组（如「核心仓位」「关注观察」等）</li></ul><h2 id="列表信息" tabindex="-1">列表信息 <a class="header-anchor" href="#列表信息" aria-label="Permalink to &quot;列表信息&quot;">​</a></h2><p>每行标的显示：</p><ul><li>标的名称 + 代码（股票、期权合约代码均支持）</li><li>迷你走势图（近期价格趋势）</li><li>最新价</li><li>涨跌幅（绿涨红跌）</li></ul><p>列表支持按「最新价」「涨跌幅」「添加时间」排序，点击列头切换。</p><h2 id="操作入口" tabindex="-1">操作入口 <a class="header-anchor" href="#操作入口" aria-label="Permalink to &quot;操作入口&quot;">​</a></h2><ul><li>右上角<strong>搜索图标</strong>：搜索并添加新标的</li><li>右上角<strong>铃铛图标</strong>：设置价格提醒（也可在标的详情页设置目标价格，触发后 App 推送通知）</li><li>标的列表右上角 <strong><code>+</code></strong>：快速添加自选</li><li>标的<strong>右滑</strong>：删除或移至其他分组</li></ul><h2 id="自定义分组管理" tabindex="-1">自定义分组管理 <a class="header-anchor" href="#自定义分组管理" aria-label="Permalink to &quot;自定义分组管理&quot;">​</a></h2><ol><li>进入自选列表，点击右上角编辑图标</li><li>选择「新建分组」，输入分组名称</li><li>将已有标的拖入对应分组，或在添加标的时直接选择目标分组</li></ol>',13)])])}const _=t(r,[["render",o]]);export{u as __pageData,_ as default};
